// dashboardFixLabel maps a rule ID to a human-readable action label for the dashboard.
func dashboardFixLabel(ctx context.Context, ruleID string) string {
	// Check exact matches first (longer prefixes before shorter ones).
	if strings.HasPrefix(ruleID, "nfo_has_mbid") {
		return t(ctx, "dashboard.fix.search_mbid")
	}
	if strings.HasPrefix(ruleID, "nfo_exists") {
		return t(ctx, "dashboard.fix.generate_nfo")
	}
	if strings.HasPrefix(ruleID, "extraneous") {
		return t(ctx, "dashboard.fix.review")
	}
	imagePrefixes := []string{"thumb", "fanart", "logo", "banner", "backdrop"}
	for _, prefix := range imagePrefixes {
		if strings.HasPrefix(ruleID, prefix) {
			return t(ctx, "dashboard.fix.fetch_image")
		}
	}
	metaPrefixes := []string{"bio", "artist"}
	for _, prefix := range metaPrefixes {
		if strings.HasPrefix(ruleID, prefix) {
			return t(ctx, "dashboard.fix.fetch_metadata")
		}
	}
	return t(ctx, "dashboard.fix.fix")
}

// severityBadgeClass returns Tailwind classes for a severity badge.
func severityBadgeClass(severity string) string {
	switch severity {
	case "error":
		return "inline-flex items-center rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-red-700 dark:text-red-300 bg-red-100 dark:bg-red-900/30"
	case "warning":
		return "inline-flex items-center rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-amber-700 dark:text-amber-300 bg-amber-100 dark:bg-amber-900/30"
	default:
		return "inline-flex items-center rounded px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wide text-blue-700 dark:text-blue-300 bg-blue-100 dark:bg-blue-900/30"
	}
}

// dashboardTimeAgo returns a human-readable relative timestamp.
func dashboardTimeAgo(ctx context.Context, ts time.Time) string {
	dur := time.Since(ts)
	switch {
	case dur < time.Minute:
		return t(ctx, "time.just_now")
	case dur < time.Hour:
		return tn(ctx, "time.minutes_ago", int(dur.Minutes()))
	case dur < 24*time.Hour:
		return tn(ctx, "time.hours_ago", int(dur.Hours()))
	case dur < 7*24*time.Hour:
		return tn(ctx, "time.days_ago", int(dur.Hours()/24))
	default:
		layout := t(ctx, "time.date_format_short")
		if layout == "" || layout == "time.date_format_short" {
			layout = "2006-01-02"
		}
		return ts.Format(layout)
	}
}

// dashboardSourceBadgeClass returns Tailwind classes for a source badge in the dashboard sidebar.
func dashboardSourceBadgeClass(source string) string {
	if source == "revert" {
		return "bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-300"
	}
	return "bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300"
}

// categoryChipClass returns Tailwind classes for a category filter chip.
func categoryChipClass(category string, active bool) string {
	base := "inline-flex items-center rounded-full px-3 py-1 text-sm font-medium transition-all cursor-pointer"
	ring := ""
	if active {
		ring = " ring-2 ring-offset-1 dark:ring-offset-gray-900"
	}

	switch category {
	case "metadata":
		if active {
			return base + " bg-amber-100 dark:bg-amber-900/30 text-amber-800 dark:text-amber-300 ring-amber-400 dark:ring-amber-500" + ring
		}
		return base + " bg-amber-50 dark:bg-amber-900/20 text-amber-700 dark:text-amber-400 hover:bg-amber-100 dark:hover:bg-amber-900/30"
	case "image":
		if active {
			return base + " bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-300 ring-red-400 dark:ring-red-500" + ring
		}
		return base + " bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400 hover:bg-red-100 dark:hover:bg-red-900/30"
	case "nfo":
		if active {
			return base + " bg-indigo-100 dark:bg-indigo-900/30 text-indigo-800 dark:text-indigo-300 ring-indigo-400 dark:ring-indigo-500" + ring
		}
		return base + " bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-400 hover:bg-indigo-100 dark:hover:bg-indigo-900/30"
	case "other":
		if active {
			return base + " bg-gray-200 dark:bg-gray-700 text-gray-800 dark:text-gray-200 ring-gray-400 dark:ring-gray-500" + ring
		}
		return base + " bg-gray-100 dark:bg-gray-700/50 text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700"
	default:
		// "All" chip
		if active {
			return base + " bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-300 ring-blue-400 dark:ring-blue-500" + ring
		}
		return base + " bg-blue-50 dark:bg-blue-900/20 text-blue-700 dark:text-blue-400 hover:bg-blue-100 dark:hover:bg-blue-900/30"
	}
}

// dashboardCategoryLabel returns the display name for a violation category on the dashboard.
func dashboardCategoryLabel(ctx context.Context, category string) string {
	key := "dashboard.category." + category
	result := t(ctx, key)
	if result == key {
		if category != "" && category != "other" {
			return category
		}
		return t(ctx, "dashboard.category.other")
	}
	return result
}

